import React, { useMemo, useState } from 'react';
import { Button, Input, Modal, Checkbox, SearchInput, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { AccountDto } from '../../../services/master/models';
import { createAccountSearchConfig, clearAccountSearchCache } from '../../../components/search';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import {
  CatalogFormFooter,
  CatalogListPagination,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
} from '../../../components/catalog';

import { useCompanyLabelMap } from '../../../hooks/useCompanyLabelMap';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const TEST_ID = 'dm-tai-khoan';

type FormErrors = Partial<Record<'code' | 'name', string>>;

const TaiKhoanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { sessionCompanyId } = useCompanyLabelMap();
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<AccountDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<AccountDto | null>(null);
  const parentAccountSearchConfig = useMemo(
    () => createAccountSearchConfig({ mode: 'all' }),
    [],
  );
  const [form, setForm] = useState<Partial<AccountDto>>({ isActive: true, isDetail: false });
  const [parentAccountName, setParentAccountName] = useState('');
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [deleteCode, setDeleteCode] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
    });
  };
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getAccounts({ search: search.trim() || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải tài khoản', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, dispatch]);

  React.useEffect(() => {
    if (!modalOpen || !form.parentCode?.trim()) {
      if (!form.parentCode) setParentAccountName('');
      return;
    }
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getAccounts({ search: form.parentCode, page: 1, pageSize: 20 }).then(res => {
        if (!cancelled) {
          const a = res.items.find(x => x.code === form.parentCode);
          setParentAccountName(a?.name ?? '');
        }
      });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [modalOpen, form.parentCode]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã tài khoản';
    if (!form.name?.trim()) next.name = 'Nhập tên tài khoản';
    return next;
  };

  const openAdd = () => {
    setEditing(null);
    setForm({ isActive: true, isDetail: false });
    setParentAccountName('');
    setErrors({});
    setModalOpen(true);
  };

  const openEdit = (row: AccountDto) => {
    setEditing(row);
    setForm({ ...row });
    setParentAccountName('');
    setErrors({});
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await masterService.updateAccount(editing.code, {
          name: form.name,
          parentCode: form.parentCode || undefined,
          isDetail: form.isDetail,
          isActive: form.isActive,
        });
      } else {
        await masterService.createAccount(form);
      }
      dispatch(addToast({
        message: editing ? 'Cập nhật tài khoản thành công' : 'Tạo tài khoản thành công',
        type: 'success',
      }));
      setModalOpen(false);
      clearAccountSearchCache();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (code: string) => {
    try {
      await masterService.deleteAccount(code);
      dispatch(addToast({ message: 'Xóa tài khoản thành công', type: 'success' }));
      setDeleteCode(null);
      clearAccountSearchCache();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-book" /> Danh mục tài khoản</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={openAdd} data-testid={`${TEST_ID}-add-btn`}>
            <i className="fas fa-plus" /> Thêm tài khoản
          </Button>
        </div>
      </div>

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách tài khoản"
        showTableLoading={showTableLoading}
        footer={
          <CatalogListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={setPage}
            onPageSizeChange={setPageSize}
          />
        }
        filters={
          <>
            <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
              <Input
                placeholder="Tìm mã, tên, TK cha..."
                value={searchDraft}
                onChange={e => setSearchDraft(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
              />
            </div>
            <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} showSearch={true} />
          </>
        }
      >
        {items.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>Tên</th>
                  <CatalogCompanyTh />
                  <th>TK cha</th>
                  <th>Chi tiết</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.code}>
                    <td><code>{r.code}</code></td>
                    <td>{r.name}</td>
                    <CatalogCompanyTd companyId={r.companyId} />
                    <td>{r.parentCode ?? '—'}</td>
                    <td>{r.isDetail ? 'Có' : 'Không'}</td>
                    <td>
                      <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                        {r.isActive ? 'Dùng' : 'Ngưng'}
                      </span>
                    </td>
                    <td className={styles.colActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)} title="Sửa">
                        <i className="fas fa-edit" />
                      </button>
                      <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteCode(r.code)} title="Xóa">
                        <i className="fas fa-trash" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </CatalogListShell>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={editing ? 'Sửa tài khoản' : 'Thêm tài khoản'}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã tài khoản *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên tài khoản *</label>
                <Input
                  value={form.name ?? ''}
                  error={errors.name}
                  onChange={e => {
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-parentCode`}>
              <label className={styles.label}>TK cha</label>
              <SearchInput
                config={parentAccountSearchConfig}
                value={form.parentCode ?? ''}
                primaryDisplay={form.parentCode ?? ''}
                secondaryDisplay={parentAccountName}
                clearOnType
                onChange={a => {
                  if (editing?.code && a.code === editing.code) {
                    dispatch(addToast({
                      message: 'Không thể chọn chính tài khoản làm TK cha',
                      type: 'error',
                    }));
                    return;
                  }
                  setForm(f => ({ ...f, parentCode: normalizeCode(a.code) }));
                  setParentAccountName(a.name);
                }}
                onClear={() => {
                  setForm(f => ({ ...f, parentCode: undefined }));
                  setParentAccountName('');
                }}
                showLabel={false}
                showSecondaryInput={false}
                placeholder="Mã hoặc tên TK..."
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-isDetail`}>
              <Checkbox
                label="Tài khoản chi tiết"
                checked={form.isDetail ?? false}
                onChange={e => setForm(f => ({ ...f, isDetail: e.target.checked }))}
              />
            </div>
          </div>
          <CatalogFormFooter
            companyId={form.companyId ?? editing?.companyId}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => setForm(f => ({ ...f, isActive: c }))}
            onCancel={() => setModalOpen(false)}
            onSave={handleSave}
            saving={saving}
          />
        </div>
      </Modal>

      <Modal isOpen={!!deleteCode} onClose={() => setDeleteCode(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa tài khoản <code>{deleteCode}</code>?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteCode(null)}>Hủy</Button>
          <Button variant="primary" onClick={() => deleteCode && handleDelete(deleteCode)}>Xóa</Button>
        </div>
      </Modal>
    </div>
  );
};

export default TaiKhoanPage;
